/* Test driver */
public class Main {
    public static void main(String[] args) {
        NotificationService s = new NotificationService(10);
        s.registerChannel(new EmailChannel());
        Notification n = NotificationFactory.createEmailNotification("U-1","a@x.com","S","B",Priority.HIGH);
        boolean ok = s.send(n);
        System.out.println(ok && s.getSentCount() == 1 ? "SEND_OK" : "SEND_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        NotificationService s = new NotificationService(2);
        s.registerChannel(new EmailChannel());
        s.send(NotificationFactory.createEmailNotification("U-1","a@x.com","S1","B",Priority.LOW));
        s.send(NotificationFactory.createEmailNotification("U-1","a@x.com","S2","B",Priority.LOW));
        s.send(NotificationFactory.createEmailNotification("U-1","a@x.com","S3","B",Priority.LOW));
        System.out.println(s.getThrottledCount() == 1 ? "THROTTLE_OK" : "THROTTLE_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        RetryDecorator retry = new RetryDecorator(new EmailChannel(), 3);
        retry.setSimulatedFailures(2);
        NotificationService s = new NotificationService(10);
        s.registerChannel(retry);
        boolean ok = s.send(NotificationFactory.createEmailNotification("U-1","a@x.com","S","B",Priority.HIGH));
        System.out.println(ok ? "RETRY_OK" : "RETRY_FAIL");
    }
}
